const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
if (!body.policy_application_id || !body.claim_description) return { json: { _empty: true, status: 400, error: 'policy_application_id and claim_description required' } };
return { json: { token: token, policy_application_id: body.policy_application_id, claim_description: String(body.claim_description).slice(0, 4000), claim_amount_estimate: parseInt(body.claim_amount_estimate) || null, incident_date: body.incident_date || null } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && rows.id ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
const i = $('Extract Inputs').item.json;
return { json: { _ok: true, reporter_user_id: row.id || row.user_id, reporter_role: row.user_role, policy_application_id: i.policy_application_id, claim_description: i.claim_description, claim_amount_estimate: i.claim_amount_estimate, incident_date: i.incident_date } };
